/**
 * Notification log model for tracking notification history.
 *
 * Each log entry represents a notification that was processed by the system,
 * capturing who received it, through which channel, and whether delivery succeeded.
 */

import type { NotificationChannel, NotificationType } from './notification.js';

export type DeliveryStatus = 'sent' | 'failed';

export interface NotificationLog {
  id: string;
  notificationId: string;
  recipient: string;
  channel: NotificationChannel;
  type: NotificationType;
  subject: string;
  status: DeliveryStatus;
  error?: string;
  timestamp: Date;
  metadata?: Record<string, unknown>;
}

/**
 * Repository for notification log data access.
 *
 * Extends BaseRepository with query methods for notification history:
 * by recipient, by type, by channel, and by date range.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import { BaseRepository } from './base.repository.js';

export class NotificationLogRepository extends BaseRepository<NotificationLog> {
  constructor(db: Database) {
    super(db, 'notification_logs');
  }

  protected toDomain(record: DatabaseRecord): NotificationLog {
    const log: NotificationLog = {
      id: record['id'] as string,
      notificationId: record['notificationId'] as string,
      recipient: record['recipient'] as string,
      channel: record['channel'] as NotificationChannel,
      type: record['type'] as NotificationType,
      subject: record['subject'] as string,
      status: record['status'] as DeliveryStatus,
      timestamp: new Date(record['timestamp'] as string),
    };
    if (record['error']) {
      log.error = record['error'] as string;
    }
    if (record['metadata']) {
      log.metadata = JSON.parse(record['metadata'] as string) as Record<string, unknown>;
    }
    return log;
  }

  protected toRecord(entity: NotificationLog): DatabaseRecord {
    const record: DatabaseRecord = {
      id: entity.id,
      notificationId: entity.notificationId,
      recipient: entity.recipient,
      channel: entity.channel,
      type: entity.type,
      subject: entity.subject,
      status: entity.status,
      timestamp: entity.timestamp.toISOString(),
    };
    if (entity.error !== undefined) {
      record['error'] = entity.error;
    }
    if (entity.metadata !== undefined) {
      record['metadata'] = JSON.stringify(entity.metadata);
    }
    return record;
  }

  findByRecipient(recipient: string): NotificationLog[] {
    return this.findAll((log) => log.recipient === recipient);
  }

  findByType(type: NotificationType): NotificationLog[] {
    return this.findAll((log) => log.type === type);
  }

  findByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.findAll((log) => log.channel === channel);
  }

  findByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.findAll((log) => log.status === status);
  }

  findByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.findAll((log) => log.timestamp >= from && log.timestamp <= to);
  }
}

/**
 * Notification history service — tracks all sent notifications.
 *
 * ARCHITECTURE:
 * This service listens to 'notification:sent' events on the EventBus and
 * persists each notification outcome to the notification log repository.
 * It provides query methods for retrieving notification history by
 * recipient, type, channel, status, and date range.
 *
 * Integration:
 * - Subscribes to 'notification:sent' events emitted by NotificationService
 * - Uses NotificationService to retrieve full notification details
 * - Persists logs via NotificationLogRepository
 *
 * Depends on:
 * - EventBus (event system)
 * - NotificationLogRepository (data access)
 * - NotificationService (to look up notification details)
 */

import type { EventBus } from '../events/event-bus.js';
import type { NotificationSentEvent } from '../events/event-types.js';
import type { NotificationLog } from '../models/notification-log.js';
import type { DeliveryStatus } from '../models/notification-log.js';
import type { NotificationChannel, NotificationType } from '../models/notification.js';
import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
import type { NotificationService } from './notification.service.js';
import { Logger } from '../utils/logger.js';

let nextLogId = 1;

function generateLogId(): string {
  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
}

export function resetLogIdCounter(): void {
  nextLogId = 1;
}

export class NotificationHistoryService {
  private logger = new Logger('NotificationHistoryService');

  constructor(
    private eventBus: EventBus,
    private logRepository: NotificationLogRepository,
    private notificationService: NotificationService,
  ) {
    this.registerEventHandlers();
  }

  private registerEventHandlers(): void {
    this.eventBus.on<NotificationSentEvent>('notification:sent', (event) => {
      return this.handleNotificationSent(event);
    });
  }

  private async handleNotificationSent(event: NotificationSentEvent): Promise<void> {
    const notification = this.notificationService
      .getNotifications()
      .find((n) => n.id === event.notificationId);

    const log: NotificationLog = {
      id: generateLogId(),
      notificationId: event.notificationId,
      recipient: notification?.recipient ?? 'unknown',
      channel: event.channel,
      type: notification?.type ?? ('unknown' as NotificationType),
      subject: notification?.subject ?? '',
      status: event.success ? 'sent' : 'failed',
      error: event.error,
      timestamp: event.timestamp,
      metadata: notification?.metadata,
    };

    this.logRepository.save(log);
    this.logger.info(
      `Logged notification ${event.notificationId} [${log.status}] via ${log.channel} to ${log.recipient}`,
    );
  }

  getHistory(): NotificationLog[] {
    return this.logRepository.findAll();
  }

  getHistoryByRecipient(recipient: string): NotificationLog[] {
    return this.logRepository.findByRecipient(recipient);
  }

  getHistoryByType(type: NotificationType): NotificationLog[] {
    return this.logRepository.findByType(type);
  }

  getHistoryByChannel(channel: NotificationChannel): NotificationLog[] {
    return this.logRepository.findByChannel(channel);
  }

  getHistoryByStatus(status: DeliveryStatus): NotificationLog[] {
    return this.logRepository.findByStatus(status);
  }

  getHistoryByDateRange(from: Date, to: Date): NotificationLog[] {
    return this.logRepository.findByDateRange(from, to);
  }

  getLogCount(): number {
    return this.logRepository.count();
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
