  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import { Database } from '../../src/utils/database.js';
import type {
  OrderCreatedEvent,
  OrderStatusChangedEvent,
  NotificationSendEvent,
} from '../../src/events/event-types.js';

describe('NotificationHistoryService', () => {
  let db: Database;
  let eventBus: EventBus;
  let notificationService: NotificationService;
  let historyService: NotificationHistoryService;
  let logRepository: NotificationLogRepository;
  let emailAdapter: EmailAdapter;

  beforeEach(() => {
    db = new Database();
    eventBus = new EventBus();
    notificationService = new NotificationService(eventBus);
    logRepository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(eventBus, logRepository, notificationService);
    emailAdapter = new EmailAdapter();
    notificationService.registerAdapter(emailAdapter);
    resetNotificationIdCounter();
    resetLogIdCounter();
  });

  function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
    return {
      type: 'order:created',
      order: {
        id: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
        total: 20,
        status: 'pending',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      user: {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      },
      timestamp: new Date(),
      ...overrides,
    };
  }

  describe('logging sent notifications', () => {
    it('should log a notification when notification:sent is emitted', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const history = historyService.getHistory();
      expect(history).toHaveLength(1);
      expect(history[0]?.notificationId).toBe('notif-0001');
      expect(history[0]?.recipient).toBe('alice@example.com');
      expect(history[0]?.channel).toBe('email');
      expect(history[0]?.type).toBe('order:confirmation');
      expect(history[0]?.status).toBe('sent');
      expect(history[0]?.id).toBe('nlog-0001');
    });

    it('should log multiple notifications', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };
      await eventBus.emit(statusEvent);

      expect(historyService.getLogCount()).toBe(2);
      const history = historyService.getHistory();
      expect(history[0]?.id).toBe('nlog-0001');
      expect(history[1]?.id).toBe('nlog-0002');
    });

    it('should capture subject from the notification', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const history = historyService.getHistory();
      expect(history[0]?.subject).toContain('Order Confirmation');
    });

    it('should capture metadata from the notification', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const history = historyService.getHistory();
      expect(history[0]?.metadata).toEqual(
        expect.objectContaining({ orderId: 'order-1', userId: 'user-1' }),
      );
    });
  });

  describe('query by recipient', () => {
    it('should return logs for a specific recipient', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      await eventBus.emit(
        makeOrderCreatedEvent({
          user: {
            id: 'user-2',
            name: 'Bob',
            email: 'bob@example.com',
            role: 'member',
            createdAt: new Date(),
            updatedAt: new Date(),
          },
          order: {
            id: 'order-2',
            userId: 'user-2',
            items: [{ productId: 'p1', name: 'Gadget', quantity: 1, unitPrice: 15 }],
            total: 15,
            status: 'pending',
            createdAt: new Date(),
            updatedAt: new Date(),
          },
        }),
      );

      const aliceLogs = historyService.getHistoryByRecipient('alice@example.com');
      expect(aliceLogs).toHaveLength(1);
      expect(aliceLogs[0]?.recipient).toBe('alice@example.com');

      const bobLogs = historyService.getHistoryByRecipient('bob@example.com');
      expect(bobLogs).toHaveLength(1);
      expect(bobLogs[0]?.recipient).toBe('bob@example.com');

      expect(historyService.getHistoryByRecipient('nobody@example.com')).toHaveLength(0);
    });
  });

  describe('query by type', () => {
    it('should return logs for a specific notification type', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const statusEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 20,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };
      await eventBus.emit(statusEvent);

      const confirmations = historyService.getHistoryByType('order:confirmation');
      expect(confirmations).toHaveLength(1);
      expect(confirmations[0]?.type).toBe('order:confirmation');

      const statusUpdates = historyService.getHistoryByType('order:status-update');
      expect(statusUpdates).toHaveLength(1);
      expect(statusUpdates[0]?.type).toBe('order:status-update');
    });
  });

  describe('query by channel', () => {
    it('should return logs for a specific channel', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const emailLogs = historyService.getHistoryByChannel('email');
      expect(emailLogs).toHaveLength(1);

      const webhookLogs = historyService.getHistoryByChannel('webhook');
      expect(webhookLogs).toHaveLength(0);
    });
  });

  describe('query by date range', () => {
    it('should return logs within the specified date range', async () => {
      const before = new Date('2025-01-01T00:00:00Z');
      const during = new Date('2025-06-15T12:00:00Z');
      const after = new Date('2025-12-31T23:59:59Z');

      await eventBus.emit(makeOrderCreatedEvent({ timestamp: during }));

      const inRange = historyService.getHistoryByDateRange(before, after);
      expect(inRange).toHaveLength(1);

      const outOfRange = historyService.getHistoryByDateRange(
        new Date('2024-01-01'),
        new Date('2024-12-31'),
      );
      expect(outOfRange).toHaveLength(0);
    });
  });

  describe('query by status', () => {
    it('should return logs with the specified delivery status', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      const sent = historyService.getHistoryByStatus('sent');
      expect(sent).toHaveLength(1);

      const failed = historyService.getHistoryByStatus('failed');
      expect(failed).toHaveLength(0);
    });
  });

  describe('notification:send event', () => {
    it('should log notifications triggered via notification:send', async () => {
      const event: NotificationSendEvent = {
        type: 'notification:send',
        payload: {
          type: 'user:welcome',
          recipient: 'charlie@example.com',
          subject: 'Welcome!',
          body: 'Welcome to TaskFlow Pro.',
        },
        channels: ['email'],
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      const history = historyService.getHistory();
      expect(history).toHaveLength(1);
      expect(history[0]?.recipient).toBe('charlie@example.com');
      expect(history[0]?.type).toBe('user:welcome');
      expect(history[0]?.channel).toBe('email');
    });
  });

  describe('persistence', () => {
    it('should persist logs to the repository', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      // Query directly from repository to verify persistence
      const repoLogs = logRepository.findAll();
      expect(repoLogs).toHaveLength(1);
      expect(repoLogs[0]?.notificationId).toBe('notif-0001');
    });

    it('should persist logs that survive service recreation', async () => {
      await eventBus.emit(makeOrderCreatedEvent());

      // Create a new history service with the same repository
      const newEventBus = new EventBus();
      const newNotificationService = new NotificationService(newEventBus);
      const newHistoryService = new NotificationHistoryService(
        newEventBus,
        logRepository,
        newNotificationService,
      );

      // Logs should still be queryable from the repository
      const history = newHistoryService.getHistory();
      expect(history).toHaveLength(1);
      expect(history[0]?.recipient).toBe('alice@example.com');
    });
  });
});

